component.script:
sub init() m.top.functionName = "execute" end sub
sub execute() request = m.top.request requestId = 0 if request <> invalid and request.DoesExist("requestId") then requestId = request.requestId m.top.status = { requestId: requestId, providerId: "", stage: "starting", message: "Preparing provider load ..." }
if request = invalid then response = Iptv_EmptyCatalogResponse("No provider was requested.") response.requestId = requestId response.providerId = "" response.metadata = { stage: "request_missing" } m.top.response = response return end if
provider = invalid if request.DoesExist("provider") then provider = request.provider if provider = invalid then response = Iptv_EmptyCatalogResponse("No provider was requested.") response.requestId = requestId response.providerId = "" response.metadata = { stage: "provider_missing" } m.top.response = response return end if
m.top.status = { requestId: requestId, providerId: Iptv_SafeString(provider.id), stage: "load_started", message: "Load started: " + Iptv_SafeString(provider.title) }
response = IptvCatalogService_LoadProvider(provider, m.top, requestId) response.requestId = requestId response.providerId = Iptv_SafeString(provider.id) if not response.DoesExist("metadata") or response.metadata = invalid then response.metadata = {} m.top.status = { requestId: requestId, providerId: response.providerId, stage: Iptv_SafeString(response.metadata.stage), message: "Load finished: " + Iptv_SafeString(response.providerId) } m.top.response = response end sub
